module hash_table (
    input [4:0] addr,
    output reg [2:0] hash_value
);
    always @(*) begin
        case (addr)
            5'b00000: hash_value = 3'b000;
            5'b00001: hash_value = 3'b001;
            5'b00010: hash_value = 3'b010;
            5'b00011: hash_value = 3'b011;
            5'b00100: hash_value = 3'b100;
            5'b00101: hash_value = 3'b101;
            5'b00110: hash_value = 3'b110;
            5'b00111: hash_value = 3'b111;
            5'b01000: hash_value = 3'b000;
            5'b01001: hash_value = 3'b001;
            5'b01010: hash_value = 3'b010;
            5'b01011: hash_value = 3'b011;
            5'b01100: hash_value = 3'b100;
            5'b01101: hash_value = 3'b101;
            5'b01110: hash_value = 3'b110;
            5'b01111: hash_value = 3'b111;
            5'b10000: hash_value = 3'b000;
            5'b10001: hash_value = 3'b001;
            5'b10010: hash_value = 3'b010;
            5'b10011: hash_value = 3'b011;
            5'b10100: hash_value = 3'b100;
            5'b10101: hash_value = 3'b101;
            5'b10110: hash_value = 3'b110;
            5'b10111: hash_value = 3'b111;
            5'b11000: hash_value = 3'b000;
            5'b11001: hash_value = 3'b001;
            5'b11010: hash_value = 3'b010;
            5'b11011: hash_value = 3'b011;
            5'b11100: hash_value = 3'b100;
            5'b11101: hash_value = 3'b101;
            5'b11110: hash_value = 3'b110;
            5'b11111: hash_value = 3'b111;
            default: hash_value = 3'b000;
        endcase
    end
endmodule
